#include <stdio.h>
#include <signal.h>
#include <string.h>
#include <unistd.h>

volatile sig_atomic_t rt_count = 0;
volatile int last_value = 0;

void rt_handler(int sig, siginfo_t *info, void *ctx) {
    (void)sig; (void)ctx;
    last_value = info->si_value.sival_int;
    rt_count++;
}

int main(void) {
    int signo = SIGRTMIN + 1;
    printf("Using RT signal: %d\n", signo);
    printf("SIGRTMIN=%d SIGRTMAX=%d range=%d\n",
           SIGRTMIN, SIGRTMAX, SIGRTMAX - SIGRTMIN);

    struct sigaction sa;
    memset(&sa, 0, sizeof(sa));
    sa.sa_sigaction = rt_handler;
    sa.sa_flags = SA_SIGINFO;
    sigemptyset(&sa.sa_mask);
    sigaction(signo, &sa, NULL);
    printf("RT handler installed\n");

    /* Envoyer 3 signaux avec des valeurs differentes */
    union sigval val;
    for (int i = 1; i <= 3; i++) {
        val.sival_int = i * 10;
        sigqueue(getpid(), signo, val);
    }

    printf("RT signals received: %d\n", rt_count);
    printf("Last value: %d\n", last_value);
    return 0;
}

